/// <summary>
/// <c>ETGProdTableCreate_Prodtable_Extension</c> extension class to handle the controls and validations.
/// </summary>
[ExtensionOf(formDataSourceStr(ProdTableCreate, ProdTable))]
internal final class ETGProdTableCreate_Prodtable_Extension
{
}

Method.Source:
public int active()
{
    int ret = next active();

    FormRun             formRun;
    FormControl         salesIdControl,ETGParentEntityControl,ETGParentWareHouseControl,itemIdControl;

    ProdTable   prodTable   = this.cursor();
    formRun                 = this.formRun();

    salesIdControl              = formRun.design().controlName(formControlStr(ProdTableCreate, ProdTable_ETGSalesId));
    ETGParentEntityControl      = formRun.design().controlName(formControlStr(ProdTableCreate, ProdTable_ETGParentEntity));
    ETGParentWareHouseControl   = formRun.design().controlName(formControlStr(ProdTableCreate, ProdTable_ETGParentWareHouse));
    itemIdControl               = formRun.design().controlName(formControlStr(ProdTableCreate, ProdTable_ETGItemId));

    if (prodTable.ETGIsSubContractingOrder == NoYes::Yes)
    {
        salesIdControl.enabled(true);
        itemIdControl.enabled(true);
        this.object(fieldNum(ProdTable, ETGParentEntity)).mandatory(true);
        this.object(fieldNum(ProdTable, ETGParentWareHouse)).mandatory(true);
    }
    else
    {
        salesIdControl.enabled(false);
        itemIdControl.enabled(false);
        ETGParentEntityControl.enabled(false);
        ETGParentWareHouseControl.enabled(false);
    }
    return ret;
}
